############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "PGlateximage.pl", "contextFraction.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Fraction"); $slope = Fraction(3,4);
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis}[ width=0.47\orccaprintwidth, xmin = -5, ymin = -5, xmax = 7, ymax = 7, ylabel={\(f(x)\)} ] \addplot+[domain = -5:7] {3/4*x+2}; \addplot[soliddot] coordinates {(-2,0.5) (-1,1.25) (0,2) (1,2.75) (2,3.5) (3,4.25) (4,5) (5, 5.75)}; \addplot[guideline] coordinates {(0,2) (4,2)} node[pos=0.5,below] {\(4\)}; \addplot[guideline] coordinates {(4,2) (4,5)} node[pos=0.5,right] {\(3\)}; \addplot[soliddot] coordinates {(0,2)} node[above left] {\((0,2)\)}; \addplot[soliddot] coordinates {(4,5)} node[above left] {\((4,5)\)}; \end{axis} \end{tikzpicture}
